import sqlite3

def build_query(search_criteria):
    query_parts = []
    for criterion in search_criteria:
        field = criterion['field']
        op = criterion['op']
        value = criterion['value']
        
        if op == '=':
            query_parts.append(f"{field} = ?")
        elif op == '>':
            query_parts.append(f"{field} > ?")
        elif op == '<':
            query_parts.append(f"{field} < ?")
        elif op == 'LIKE':
            query_parts.append(f"{field} LIKE ?")
    
    query = "SELECT * FROM users WHERE " + " AND ".join(query_parts)
